choose.when:
UPDATE
    FOREIGN_CONSIGNMENT_ORDER
SET
    ACCEPT_ORDER_NO = #{req.orderNumber}
    , ACCEPT_ORDER_SUB_NO = #{req.orderSubNumber}
    , ORDER_DATE = TO_CHAR(#{req.orderDateTime}, 'YYYYMMDD')
    , ORDER_TIME = #{req.orderDateTime}
    , TRADE_LIMIT_DATE = #{req.period}
    , API_ERROR_CODE = null
    , API_STATUS_CODE = #{req.responseCode}
    , API_MESSAGE = null
    , UPDATE_TIME = IFA_DATE_UTIL.IFA_GET_DATE
    , UPDATE_USER = #{req.userId}
WHERE
    IFA_ORDER_NO = #{req.ifaOrderNo}
    AND IFA_ORDER_SUB_NO = #{req.ifaOrderSubNo}

choose.otherwise:
UPDATE
    FOREIGN_CONSIGNMENT_ORDER
SET
    API_ERROR_CODE = #{req.errorCode}
    , API_STATUS_CODE = #{req.responseCode}
    , API_MESSAGE = SUBSTRB(#{req.errMessage}, 1, 100)
    , UPDATE_TIME = IFA_DATE_UTIL.IFA_GET_DATE
    , UPDATE_USER = #{req.userId}
WHERE
    IFA_ORDER_NO = #{req.ifaOrderNo}
    AND IFA_ORDER_SUB_NO = #{req.ifaOrderSubNo}
